7	BeforeAll {
8	    $script:ScriptPath = Join-Path $PSScriptRoot 'Invoke-ArtifactCleanup.ps1'
9	
10	    # Helper: run the cleanup script with given parameters and return parsed output
11	    function Invoke-Cleanup {
12	        param(
13	            [string]$ArtifactsJson,
14	            [int]$MaxAgeDays = -1,
15	            [long]$MaxTotalSizeBytes = -1,
16	            [int]$KeepLatestN = -1,
17	            [switch]$DryRun,
18	            [string]$ReferenceDate = "2026-01-15"
19	        )
20	
21	        $params = @(
22	            '-NoProfile', '-NonInteractive', '-File', $script:ScriptPath,
23	            '-ArtifactsJson', $ArtifactsJson,
24	            '-ReferenceDate', $ReferenceDate
25	        )
26	        if ($MaxAgeDays -ge 0)       { $params += '-MaxAgeDays';       $params += $MaxAgeDays }
27	        if ($MaxTotalSizeBytes -ge 0) { $params += '-MaxTotalSizeBytes'; $params += $MaxTotalSizeBytes }
28	        if ($KeepLatestN -ge 0)       { $params += '-KeepLatestN';     $params += $KeepLatestN }
29	        if ($DryRun)                  { $params += '-DryRun' }
30	
31	        $output = & pwsh @params 2>&1
32	        $outputText = $output -join "`n"
33	
34	        # Extract JSON plan from between markers
35	        $jsonPlan = $null
36	        if ($outputText -match 'JSON_PLAN_START\s*([\s\S]*?)\s*JSON_PLAN_END') {
37	            $jsonPlan = $Matches[1] | ConvertFrom-Json
38	        }
39	
40	        return @{
41	            RawOutput = $outputText
42	            Plan      = $jsonPlan
43	        }
44	    }
45	}
46	
