48	# Common mock artifacts used across tests
49	BeforeAll {
50	    # 5 artifacts across 2 workflow runs
51	    $script:MockArtifacts = @(
52	        @{ name = "build-log-1"; size = 1000; createdAt = "2026-01-01"; workflowRunId = "run-100" }
53	        @{ name = "build-log-2"; size = 2000; createdAt = "2026-01-05"; workflowRunId = "run-100" }
54	        @{ name = "build-log-3"; size = 3000; createdAt = "2026-01-10"; workflowRunId = "run-100" }
55	        @{ name = "test-results-1"; size = 500;  createdAt = "2026-01-03"; workflowRunId = "run-200" }
56	        @{ name = "test-results-2"; size = 1500; createdAt = "2026-01-12"; workflowRunId = "run-200" }
57	    ) | ConvertTo-Json -Compress
58	
59	    $script:SingleArtifact = @(
60	        @{ name = "only-one"; size = 5000; createdAt = "2026-01-14"; workflowRunId = "run-300" }
61	    ) | ConvertTo-Json -Compress
62	}
