64	Describe "Artifact Cleanup Script" {
65	
66	    Context "Basic parsing and empty input" {
67	
68	        It "Should handle empty array input" {
69	            $result = Invoke-Cleanup -ArtifactsJson '[]'
70	            $result.Plan.TotalArtifacts | Should -Be 0
71	            $result.Plan.ArtifactsToDelete | Should -Be 0
72	            $result.Plan.SpaceReclaimed | Should -Be 0
73	        }
74	
75	        It "Should parse and return all artifacts when no policies applied" {
76	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts
77	            $result.Plan.TotalArtifacts | Should -Be 5
78	            $result.Plan.ArtifactsToDelete | Should -Be 0
79	            $result.Plan.ArtifactsToRetain | Should -Be 5
80	        }
81	    }
82	
83	    Context "Max age policy" {
84	
85	        It "Should delete artifacts older than MaxAgeDays" {
86	            # Reference date 2026-01-15, MaxAgeDays=10
87	            # build-log-1 (Jan 1) = 14 days old -> DELETE
88	            # test-results-1 (Jan 3) = 12 days old -> DELETE
89	            # build-log-2 (Jan 5) = 10 days old -> KEEP (not strictly greater)
90	            # build-log-3 (Jan 10) = 5 days old -> KEEP
91	            # test-results-2 (Jan 12) = 3 days old -> KEEP
92	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10
93	            $result.Plan.ArtifactsToDelete | Should -Be 2
94	            $result.Plan.ArtifactsToRetain | Should -Be 3
95	            $result.Plan.SpaceReclaimed | Should -Be 1500
96	        }
97	
98	        It "Should delete all artifacts when MaxAgeDays is 0" {
99	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 0
100	            $result.Plan.ArtifactsToDelete | Should -Be 5
101	            $result.Plan.ArtifactsToRetain | Should -Be 0
102	            $result.Plan.SpaceReclaimed | Should -Be 8000
103	        }
104	
105	        It "Should retain all artifacts when none are old enough" {
106	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 30
107	            $result.Plan.ArtifactsToDelete | Should -Be 0
108	            $result.Plan.ArtifactsToRetain | Should -Be 5
109	        }
110	    }
111	
112	    Context "Keep-latest-N per workflow policy" {
113	
114	        It "Should keep only N most recent artifacts per workflow" {
115	            # run-100 has 3 artifacts: keep latest 1 -> delete 2 oldest
116	            # run-200 has 2 artifacts: keep latest 1 -> delete 1 oldest
117	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -KeepLatestN 1
118	            $result.Plan.ArtifactsToDelete | Should -Be 3
119	            $result.Plan.ArtifactsToRetain | Should -Be 2
120	            # Retained: build-log-3 (3000) + test-results-2 (1500) = 4500
121	            $result.Plan.SpaceRetained | Should -Be 4500
122	        }
123	
124	        It "Should keep all when N is greater than group size" {
125	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -KeepLatestN 10
126	            $result.Plan.ArtifactsToDelete | Should -Be 0
127	            $result.Plan.ArtifactsToRetain | Should -Be 5
128	        }
129	
130	        It "Should keep latest 2 per workflow" {
131	            # run-100: keep build-log-3, build-log-2; delete build-log-1
132	            # run-200: keep both (only 2)
133	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -KeepLatestN 2
134	            $result.Plan.ArtifactsToDelete | Should -Be 1
135	            $result.Plan.ArtifactsToRetain | Should -Be 4
136	            $result.Plan.SpaceReclaimed | Should -Be 1000
137	        }
138	    }
139	
140	    Context "Max total size policy" {
141	
142	        It "Should delete oldest artifacts when total exceeds max size" {
143	            # Total = 8000 bytes. Max = 5000.
144	            # Need to reclaim 3000. Delete oldest first:
145	            # build-log-1 (Jan 1, 1000) -> total now 7000, still > 5000
146	            # test-results-1 (Jan 3, 500) -> total now 6500, still > 5000
147	            # build-log-2 (Jan 5, 2000) -> total now 4500, <= 5000 STOP
148	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxTotalSizeBytes 5000
149	            $result.Plan.ArtifactsToDelete | Should -Be 3
150	            $result.Plan.ArtifactsToRetain | Should -Be 2
151	            $result.Plan.SpaceReclaimed | Should -Be 3500
152	            $result.Plan.SpaceRetained | Should -Be 4500
153	        }
154	
155	        It "Should retain all when total is already under max" {
156	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxTotalSizeBytes 99999
157	            $result.Plan.ArtifactsToDelete | Should -Be 0
158	            $result.Plan.ArtifactsToRetain | Should -Be 5
159	        }
160	
161	        It "Should delete all if max size is 0" {
162	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxTotalSizeBytes 0
163	            $result.Plan.ArtifactsToDelete | Should -Be 5
164	            $result.Plan.ArtifactsToRetain | Should -Be 0
165	            $result.Plan.SpaceReclaimed | Should -Be 8000
166	        }
167	    }
168	
169	    Context "Combined policies" {
170	
171	        It "Should apply max-age AND keep-latest-N together" {
172	            # MaxAgeDays=10: deletes build-log-1 (14d), test-results-1 (12d)
173	            # KeepLatestN=1: from remaining {build-log-2, build-log-3, test-results-2}
174	            #   run-100: build-log-3 kept, build-log-2 deleted
175	            #   run-200: test-results-2 kept (only one left)
176	            # Total deleted: build-log-1, test-results-1, build-log-2 = 3
177	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10 -KeepLatestN 1
178	            $result.Plan.ArtifactsToDelete | Should -Be 3
179	            $result.Plan.ArtifactsToRetain | Should -Be 2
180	            $result.Plan.SpaceRetained | Should -Be 4500
181	        }
182	
183	        It "Should apply all three policies together" {
184	            # MaxAgeDays=10: deletes build-log-1, test-results-1
185	            # KeepLatestN=2: no additional deletions (run-100 has 2 left, run-200 has 1)
186	            # MaxTotalSizeBytes=4000: remaining = build-log-2(2000)+build-log-3(3000)+test-results-2(1500) = 6500
187	            #   Need to remove 2500. Oldest first: build-log-2 (2000) -> 4500, still > 4000
188	            #   Then test-results-2 (1500) -> 3000, <= 4000 STOP
189	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10 -KeepLatestN 2 -MaxTotalSizeBytes 4000
190	            $result.Plan.ArtifactsToDelete | Should -Be 4
191	            $result.Plan.ArtifactsToRetain | Should -Be 1
192	            $result.Plan.SpaceRetained | Should -Be 3000
193	        }
194	    }
195	
196	    Context "Dry-run mode" {
197	
198	        It "Should indicate dry run in output" {
199	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10 -DryRun
200	            $result.RawOutput | Should -Match "DRY RUN MODE"
201	            $result.Plan.DryRun | Should -Be $true
202	        }
203	
204	        It "Should indicate execution mode when not dry-run" {
205	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10
206	            $result.RawOutput | Should -Match "EXECUTION MODE"
207	            $result.Plan.DryRun | Should -Be $false
208	        }
209	    }
210	
211	    Context "Single artifact edge case" {
212	
213	        It "Should handle single artifact with keep-latest-1" {
214	            $result = Invoke-Cleanup -ArtifactsJson $script:SingleArtifact -KeepLatestN 1
215	            $result.Plan.TotalArtifacts | Should -Be 1
216	            $result.Plan.ArtifactsToRetain | Should -Be 1
217	            $result.Plan.ArtifactsToDelete | Should -Be 0
218	        }
219	    }
220	
221	    Context "Output format" {
222	
223	        It "Should list deleted artifacts with reasons" {
224	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10
225	            $result.RawOutput | Should -Match "Artifacts to delete:"
226	            $result.RawOutput | Should -Match "build-log-1"
227	            $result.RawOutput | Should -Match "Reason:"
228	        }
229	
230	        It "Should list retained artifacts" {
231	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10
232	            $result.RawOutput | Should -Match "Artifacts retained:"
233	            $result.RawOutput | Should -Match "build-log-3"
234	        }
235	
236	        It "Should include summary counts" {
237	            $result = Invoke-Cleanup -ArtifactsJson $script:MockArtifacts -MaxAgeDays 10
238	            $result.RawOutput | Should -Match "Total artifacts: 5"
239	            $result.RawOutput | Should -Match "To delete: 2"
240	            $result.RawOutput | Should -Match "To retain: 3"
241	            $result.RawOutput | Should -Match "Space reclaimed: 1500 bytes"
242	        }
243	    }
244	}
